script:
export const meta = {
  name: 'pass9-verify',
  description: 'Pass-9: two independent agents blind-verify each survivor is a true positive',
  phases: [{ title: 'Verify' }],
}
const REPO = '/Users/[REDACTED]/hc-assay'
const SCHEMA = {
  type: 'object', additionalProperties: false, required: ['verdict', 'reasoning'],
  properties: { verdict: { type: 'string', enum: ['TRUE_POSITIVE', 'FALSE_POSITIVE'] }, reasoning: { type: 'string' } },
}
const FINDINGS = [
  { key: 'K-SEC-9-1', sev: 'high', title: 'K-SEC-1 Unix-socket guard bypass via libpq multi-host comma value',
    loc: 'src/assay_engine/_local.py (require_local_uri DSN/query branches + is_local_socket_path)',
    claim: `Pass-8's K-SEC-1 fix accepts a leading-"/" host as a local Unix socket. But libpq allows COMMA-SEPARATED multi-host values (e.g. host=/tmp,evil.com or host=/var/run/postgresql,[REDACTED]). If require_local_uri's DSN/query host check treats the whole comma value as one string, the leading "/" makes is_local_socket_path() return True and the off-box host after the comma is accepted → data exfiltration off-box, defeating ADR-0003. VERIFY empirically: require_local_uri('host=/tmp,evil.com', what='x') and the query form 'postgresql:///db?host=/var/run/postgresql,evil.com' — are they accepted (bug) or rejected? Check whether the authority branch splits multi-host but the DSN/query branches do not.` },
  { key: 'CI-1', sev: 'high', title: 'No enforced required status check: red CI does not block merges',
    loc: '.github/workflows/ci.yml all-checks + repo branch-protection',
    claim: `branch protection is unavailable (gh api .../branches/main/protection → 403 "Upgrade to GitHub Pro or make this repository public"), so the all-checks gate is decorative — nothing blocks merging a red PR. gh run list --branch main shows merge commits for #161/#162/#166/#167/#168 with conclusion=failure. VERIFY the 403 and that red merges occurred. NOTE for your verdict: the constraint is platform/plan-level (cannot enable branch protection without upgrading the plan or making the repo public — making it public would PUBLISH the transcripts, which is out of scope to do). Judge whether the GAP (no enforcement + no in-repo compensating control) is a real production-readiness finding regardless of the constrained remediation.` },
  { key: 'P9-PII-1', sev: 'medium', title: 'Operator internal hostname leaks into committed transcripts',
    loc: 'scripts/capture_transcripts.py (no hostname scrub rule); transcripts/sessions/.../*.jsonl',
    claim: `The scrubber covers email/username/display-name/handle but has NO hostname rule. '[REDACTED]' / '[REDACTED]' appear raw in committed transcripts (incl. a genuine PROV-O namespace https://[REDACTED]/prov# read from a real project file, not just meta-discussion). scutil --get LocalHostName returns [REDACTED]; this Mac mini is the named production node, so the hostname is operator/infra-identifying PII. VERIFY: _scrub('ran on [REDACTED]') is unchanged, and grep the corpus for raw occurrences that are genuine data.` },
  { key: 'P9-MO-1', sev: 'medium', title: 'confirm primitives raise opaque TypeError (not documented ValueError) when alpha is None',
    loc: 'src/assay_engine/methodology/confirm.py (+ hypothesis alpha resolution)',
    claim: `When alpha is None on BOTH the hypothesis and the call, the confirm primitive raises an opaque TypeError (e.g. from a None comparison/arithmetic) instead of the documented ValueError with a clear message. VERIFY by constructing such a call and checking the exception type/message vs what the docstring/contract promises.` },
  { key: 'P9-MO-2', sev: 'low', title: 'Bare int()/float() env parsing crashes import with opaque error in seam.py/checkpoint.py',
    loc: 'src/assay_engine/reasoning/seam.py + persistence/checkpoint.py (env int/float parsing)',
    claim: `seam.py and checkpoint.py parse numeric env vars with bare int()/float(), so a malformed value raises an opaque ValueError at import/use with no indication of WHICH env var — the exact class already fixed elsewhere via _int_env (tracing.py, vectorstore.py, per #H-022/#CV-S-1). VERIFY the bare int()/float() calls exist on env values and are not wrapped to name the offending var.` },
]
function prompt(f, lens) {
  return `You are an independent blind verifier (verifier ${lens}) for the hc-assay production-hardening campaign at ${REPO} (branch harden/pass-9). Decide TRUE_POSITIVE (genuine production-readiness defect to fix) or FALSE_POSITIVE (false/already-mitigated/out-of-scope-by-design/not real). Out-of-scope examples: dataset-agnostic opaque inputs; optional import-guarded backends; intentionally-committed scrubbed transcripts; on-box data-sovereignty; documented honest-scope. Read real code and REPRODUCE where testable (cd ${REPO} && source .venv/bin/activate && python ...; "python -m pytest"; gh for CI). Judge ONLY ${f.key}.\n\nFINDING ${f.key} (${f.sev}): ${f.title}\nLocation: ${f.loc}\nClaim: ${f.claim}`
}
phase('Verify')
const results = await parallel(
  FINDINGS.flatMap((f) => [
    () => agent(prompt(f, 'A'), { label: `verify:${f.key}:A`, phase: 'Verify', schema: SCHEMA }).then((v) => ({ key: f.key, sev: f.sev, lens: 'A', v })),
    () => agent(prompt(f, 'B'), { label: `verify:${f.key}:B`, phase: 'Verify', schema: SCHEMA }).then((v) => ({ key: f.key, sev: f.sev, lens: 'B', v })),
  ])
)
const clean = results.filter(Boolean)
const byKey = {}
for (const r of clean) { (byKey[r.key] = byKey[r.key] || { sev: r.sev, votes: [] }).votes.push({ lens: r.lens, ...r.v }) }
const summary = Object.entries(byKey).map(([key, o]) => ({ key, sev: o.sev, bothTP: o.votes.length === 2 && o.votes.every((x) => x.verdict === 'TRUE_POSITIVE'), votes: o.votes }))
log('PASS-9 VERIFICATION:')
for (const s of summary) log(`${s.key} (${s.sev}): ${s.bothTP ? 'BOTH TRUE_POSITIVE → fix' : 'SPLIT/REJECTED'} — ${s.votes.map((v) => v.lens + ':' + v.verdict).join(', ')}`)
return { summary }
